import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

/**
 * Tests for extension properties with custom getters that have annotations or visibility modifiers.
 * See: https://github.com/pinterest/ktlint/issues/2033
 */
class PropertyNamingRuleExtensionPropertyTest {
    private val propertyNamingRuleAssertThat =
        KtLintAssertThat.assertThatRule { PropertyNamingRule() }

    @Test
    fun `Given an extension property with a custom getter with annotation then do not emit`() {
        val code =
            """
            val String.someProperty @Suppress("UNCHECKED_CAST") get() = this
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an extension property with a custom getter with private modifier then do not emit`() {
        val code =
            """
            val String.someProperty private get() = this
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an extension property with a custom getter without annotation or modifier then do not emit`() {
        val code =
            """
            val String.someProperty get() = this
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a top level val property with custom getter with annotation then do not emit`() {
        val code =
            """
            val someProperty @JvmName("getSomePropertyValue") get() = "value"
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an object val property with custom getter with annotation then do not emit`() {
        val code =
            """
            class Foo {
                companion object {
                    val someProperty @JvmName("getSomePropertyValue") get() = "value"
                }
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an object val property with custom getter with private modifier then do not emit`() {
        val code =
            """
            class Foo {
                companion object {
                    val someProperty private get() = "value"
                }
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }
}
